'use client';import { FormEvent,useState } from 'react';import { Input } from '@/components/ui/input';import { PageHeader, SubmitButton } from '@/components/erp/shared';import { useRouter } from 'next/navigation';import toast from 'react-hot-toast';
export default function VendorNew(){const [loading,setLoading]=useState(false);const [f,setF]=useState({name:'',email:'',phone:'',commissionRate:'0',notes:'',active:true});const router=useRouter();const save=async(e:FormEvent)=>{e.preventDefault();setLoading(true);const r=await fetch('/api/v1/erp/sellers',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({...f,commissionRate:Number(f.commissionRate)})});setLoading(false);if(!r.ok)return toast.error('Erro');toast.success('Vendedor salvo');router.push('/dashboard/vendors')};return <div className='space-y-4'><PageHeader title='Novo vendedor' subtitle='Cadastro comercial com comissão.'/><form onSubmit={save} className='bg-white border rounded p-4 space-y-2'><Input required placeholder='Nome' value={f.name} onChange={e=>setF({...f,name:e.target.value})}/><Input placeholder='Email' value={f.email} onChange={e=>setF({...f,email:e.target.value})}/><Input placeholder='Telefone' value={f.phone} onChange={e=>setF({...f,phone:e.target.value})}/><Input type='number' step='0.01' placeholder='Comissão %' value={f.commissionRate} onChange={e=>setF({...f,commissionRate:e.target.value})}/><Input placeholder='Observação' value={f.notes} onChange={e=>setF({...f,notes:e.target.value})}/><label className='text-sm flex items-center gap-2'><input type='checkbox' checked={f.active} onChange={e=>setF({...f,active:e.target.checked})}/>Ativo</label><SubmitButton loading={loading}>Salvar vendedor</SubmitButton></form></div>}
